// Check if MCX is open (9:00 - 23:30 IST, Mon-Fri)
const now = new Date();
const istHour = (now.getUTCHours() + 5) % 24 + (now.getUTCMinutes() + 30 >= 60 ? 1 : 0);
const istMin = (now.getUTCMinutes() + 30) % 60;
const mcxOpen = (istHour >= 9 && (istHour < 23 || (istHour === 23 && istMin <= 30)));
return [{ json: { mcx_open: mcxOpen, ist_hour: istHour, ist_min: istMin } }];

const data = $input.first().json;
const alerts = [];

// Check for fired forex scanners
const firedBull = data.fired_bull || [];
const firedBear = data.fired_bear || [];

const forexBull = firedBull.filter(s => s.startsWith('cds_'));
const forexBear = firedBear.filter(s => s.startsWith('cds_'));
const mcxBull = firedBull.filter(s => s.startsWith('mcx_'));
const mcxBear = firedBear.filter(s => s.startsWith('mcx_'));

if (forexBull.length > 0) {
  alerts.push({ json: { text: `\u{1F4B1} CDS Forex BULL signals (${forexBull.length}):\n${forexBull.join(', ')}` } });
}
if (forexBear.length > 0) {
  alerts.push({ json: { text: `\u{1F4B1} CDS Forex BEAR signals (${forexBear.length}):\n${forexBear.join(', ')}` } });
}
if (mcxBull.length > 0) {
  alerts.push({ json: { text: `\u{26CF} MCX Commodity BULL signals (${mcxBull.length}):\n${mcxBull.join(', ')}` } });
}
if (mcxBear.length > 0) {
  alerts.push({ json: { text: `\u{26CF} MCX Commodity BEAR signals (${mcxBear.length}):\n${mcxBear.join(', ')}` } });
}

// Active chains
const chains = data.active_chains || [];
const extChains = chains.filter(c => 
  c.name.startsWith('forex_') || c.name.startsWith('commodity_') || c.name === 'gold_silver_mean_reversion'
);
for (const c of extChains) {
  alerts.push({ json: { text: `\u{1F517} Chain: ${c.name} (${c.complete ? 'COMPLETE' : 'partial'}) +${c.boost}%\n${c.desc}` } });
}

return alerts;

// Check if CDS is open (9:00 - 17:00 IST, Mon-Fri)
const now = new Date();
const istHour = (now.getUTCHours() + 5) % 24 + (now.getUTCMinutes() + 30 >= 60 ? 1 : 0);
const cdsOpen = (istHour >= 9 && istHour < 17);
return [{ json: { cds_open: cdsOpen, ist_hour: istHour } }];
